static void writeJvmClass(JvmClass jvmClass, DataOutput out) throws IOException {
    writeJVMClassNode(jvmClass, out);
    out.writeUTF(jvmClass.getSuperFqName());
    out.writeUTF(jvmClass.getOuterFqName());
    int interfacesCount = 0;
    for (String myInterface : jvmClass.getInterfaces()) interfacesCount++;
    DataInputOutputUtil.writeINT(out, interfacesCount);
    for (String myInterface : jvmClass.getInterfaces()) out.writeUTF(myInterface);
    int fieldsCount = 0;
    for (JvmField field : jvmClass.getFields()) fieldsCount++;
    DataInputOutputUtil.writeINT(out, fieldsCount);
    for (JvmField field : jvmClass.getFields()) writeJvmField(field, out);
}

after:
static void writeJvmClass(JvmClass jvmClass, DataOutput out) throws IOException {
    writeJVMClassNode(jvmClass, out);
    out.writeUTF(jvmClass.getSuperFqName());
    out.writeUTF(jvmClass.getOuterFqName());
    writeInterfaces(jvmClass, out);
    writeFields(jvmClass, out);
}

static void writeInterfaces(JvmClass jvmClass, DataOutput out) throws IOException {
    int interfacesCount = 0;
    for (String myInterface : jvmClass.getInterfaces()) interfacesCount++;
    DataInputOutputUtil.writeINT(out, interfacesCount);
    for (String myInterface : jvmClass.getInterfaces()) out.writeUTF(myInterface);
}

static void writeFields(JvmClass jvmClass, DataOutput out) throws IOException {
    int fieldsCount = 0;
    for (JvmField field : jvmClass.getFields()) fieldsCount++;
    DataInputOutputUtil.writeINT(out, fieldsCount);
    for (JvmField field : jvmClass.getFields()) writeJvmField(field, out);
}

